prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  (COUNT(DISTINCT ?msg) AS ?totalMessages)
  (COUNT(DISTINCT ?mflow) AS ?totalMessageFlows)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "2b18c5f00a5a46159c6cb6a3e2bc79e9" .

  OPTIONAL {
    ?msg a bboExt:Message ;
         tai:belongsTo+ ?choreo .
  }

  OPTIONAL {
    ?mflow a bboExt:MessageFlow ;
           tai:belongsTo+ ?choreo .
  }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT
  (COUNT(DISTINCT ?msg) AS ?totalMessages)
  (COUNT(DISTINCT ?mflow) AS ?totalMessageFlows)
WHERE {
  ?model a bboExt:Model .
  {
    ?model tai:normalizedId "2b18c5f00a5a46159c6cb6a3e2bc79e9" .
  }
  UNION
  {
    ?model tai:originalId "2b18c5f00a5a46159c6cb6a3e2bc79e9" .
  }

  OPTIONAL {
    ?msg a bboExt:Message .
    ?msg tai:belongsTo+ ?anyChoreo .
  }

  OPTIONAL {
    ?mflow a bboExt:MessageFlow .
    ?mflow tai:belongsTo+ ?anyChoreo .
  }
}

